+fn collect_rusqlite_rows<P: rusqlite::Params>(
+    stmt: &mut rusqlite::Statement<'_>,
+    params: P,
+) -> rusqlite::Result<Vec<Vec<rusqlite::types::Value>>> {
+    let col_count = stmt.column_count();
