+        let mut values = Vec::with_capacity(col_count);
+        for idx in 0..col_count {
+            let value = row.get(idx).unwrap_or(rusqlite::types::Value::Null);
+            values.push(value);
+        }
+        Ok(values)
+    })?
+    .collect::<Result<Vec<_>, _>>()
